let rawData = $input.first().json.output;
// $input.first().json.output
rawData = rawData.replace(/```json/g, '').replace(/```/g, '').trim();

const buffer = Buffer.from(rawData, 'utf8');

return [
  {
    json: {
      fileName: "generated_course.ipynb"
    },
    binary: {
      data: {
        data: buffer.toString('base64'),
        mimeType: 'application/x-ipynb+json',
        fileName: 'generated_course.ipynb',
        fileExtension: 'ipynb'
      }
    }
  }
];
